import React, { useRef, useEffect, useCallback } from 'react';

// ─── Constants ────────────────────────────────────────────────────────────────
const CHUNK_BYTES       = 20 * 1024 * 1024;  // 20 MB per chunk
const PREFETCH_CHUNKS   = 2;                  // parallel prefetch ahead
const BUFFER_AHEAD_SEC  = 30;                 // keep ≥30s buffered ahead
const BUFFER_BEHIND_SEC = 10;                 // evict buffer older than 10s behind
const DRIFT_THRESHOLD   = 0.08;              // seconds before resync
const SYNC_INTERVAL_MS  = 500;
const MAX_RETRIES       = 3;
const RETRY_BASE_MS     = 500;

// ─── Helpers ──────────────────────────────────────────────────────────────────
const sleep = ms => new Promise(r => setTimeout(r, ms));

async function fetchChunkWithRetry(url, start, end, signal) {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      const res = await fetch(url, {
        headers: { Range: `bytes=${start}-${end}` },
        signal,
      });
      if (!res.ok && res.status !== 206) throw new Error(`HTTP ${res.status}`);
      return await res.arrayBuffer();
    } catch (e) {
      if (signal.aborted || attempt === MAX_RETRIES) throw e;
      await sleep(RETRY_BASE_MS * 2 ** attempt);
    }
  }
}

async function getContentLength(url, signal) {
  try {
    const res = await fetch(url, { method: 'HEAD', signal });
    return parseInt(res.headers.get('content-length') || '0', 10);
  } catch { return 0; }
}

// ─── MSE Stream Engine ────────────────────────────────────────────────────────
// Streams video via Range requests with parallel prefetch.
// Audio is handled separately and starts immediately — no dependency on video.
class StreamEngine {
  constructor(videoEl, src) {
    this.videoEl      = videoEl;
    this.src          = src;
    this.ms           = new MediaSource();
    this.sb           = null;
    this.totalBytes   = 0;
    this.nextByte     = 0;       // next byte to fetch
    this.inflight     = 0;       // concurrent fetches in progress
    this.sbQueue      = [];      // ArrayBuffers waiting to be appended
    this.appending    = false;
    this.eos          = false;
    this.destroyed    = false;
    this.ac           = new AbortController();
    this._readyResolve = null;
    this.readyPromise = new Promise(r => { this._readyResolve = r; });
    this._objectURL   = null;
  }

  start() {
    this._objectURL = URL.createObjectURL(this.ms);
    this.videoEl.src = this._objectURL;
    this.ms.addEventListener('sourceopen', () => this._onOpen(), { once: true });
    return this.readyPromise;
  }

  async _onOpen() {
    const MIME = 'video/mp4; codecs="avc1.42E01E,mp4a.40.2"';
    if (!MediaSource.isTypeSupported(MIME)) {
      // Graceful fallback
      this.videoEl.src = this.src;
      this._readyResolve();
      return;
    }
    this.sb = this.ms.addSourceBuffer(MIME);
    this.sb.mode = 'sequence';
    this.sb.addEventListener('updateend', () => this._drainQueue());

    this.totalBytes = await getContentLength(this.src, this.ac.signal);
    this._schedulePrefetch();
  }

  // Evict stale buffer behind playhead to free memory
  _evictBehind() {
    const v = this.videoEl;
    if (!this.sb || this.sb.updating || v.buffered.length === 0) return;
    const evictEnd = v.currentTime - BUFFER_BEHIND_SEC;
    if (evictEnd > 0) {
      try { this.sb.remove(0, evictEnd); } catch {}
    }
  }

  // How many seconds are buffered ahead of currentTime
  _bufferedAhead() {
    const v = this.videoEl;
    const ct = v.currentTime;
    for (let i = 0; i < v.buffered.length; i++) {
      if (v.buffered.start(i) <= ct + 0.5 && v.buffered.end(i) > ct) {
        return v.buffered.end(i) - ct;
      }
    }
    return 0;
  }

  _isDone() {
    return this.totalBytes > 0 && this.nextByte >= this.totalBytes;
  }

  // Launch up to PREFETCH_CHUNKS parallel fetches if buffer needs filling
  _schedulePrefetch() {
    if (this.destroyed || this._isDone()) return;
    if (this._bufferedAhead() >= BUFFER_AHEAD_SEC) return;

    while (this.inflight < PREFETCH_CHUNKS && !this._isDone()) {
      this._fetchNext();
    }
  }

  async _fetchNext() {
    if (this.destroyed || this._isDone()) return;
    const start = this.nextByte;
    const end   = this.totalBytes
      ? Math.min(start + CHUNK_BYTES - 1, this.totalBytes - 1)
      : start + CHUNK_BYTES - 1;
    this.nextByte = end + 1;
    this.inflight++;

    try {
      const buf = await fetchChunkWithRetry(this.src, start, end, this.ac.signal);
      if (this.destroyed) return;
      this.sbQueue.push(buf);
      this._drainQueue();
    } catch (e) {
      if (!this.destroyed) console.warn('[StreamEngine] chunk failed', start, e);
    } finally {
      this.inflight--;
      if (!this.destroyed) this._schedulePrefetch();
    }
  }

  _drainQueue() {
    if (!this.sb || this.sb.updating || this.sbQueue.length === 0) return;
    const buf = this.sbQueue.shift();
    const isFirst = !this._readyFired;
    try {
      this.sb.appendBuffer(buf);
    } catch (e) {
      console.warn('[StreamEngine] appendBuffer error', e);
      return;
    }
    if (isFirst) {
      this._readyFired = true;
      this._readyResolve();   // first chunk appended → video can start
    }
    // After append, check if we need to signal EOS
    if (this._isDone() && this.sbQueue.length === 0 && !this.eos) {
      this.sb.addEventListener('updateend', () => {
        if (!this.eos && this.ms.readyState === 'open') {
          this.eos = true;
          try { this.ms.endOfStream(); } catch {}
        }
      }, { once: true });
    }
  }

  // Called on timeupdate / seeking to keep buffer ahead and evict behind
  onTimeUpdate() {
    this._evictBehind();
    this._schedulePrefetch();
  }

  // On seek: reset nextByte to the byte offset matching the seek time
  onSeeking() {
    if (!this.totalBytes) return;
    const v = this.videoEl;
    const ratio = v.currentTime / (v.duration || 1);
    this.nextByte = Math.floor(ratio * this.totalBytes);
    // Align to chunk boundary
    this.nextByte = Math.floor(this.nextByte / CHUNK_BYTES) * CHUNK_BYTES;
    this.inflight = 0;
    this.sbQueue  = [];
    this._schedulePrefetch();
  }

  destroy() {
    this.destroyed = true;
    this.sb = null;
    this.ac.abort();
    try { if (this.ms.readyState === 'open') this.ms.endOfStream(); } catch {}
    if (this._objectURL) { URL.revokeObjectURL(this._objectURL); this._objectURL = null; }
  }
}

// ─── Component ────────────────────────────────────────────────────────────────
const VideoAudioPlayer = ({ src, id, activeAudioId, onVisibilityChange }) => {
  const videoRef     = useRef(null);
  const audioRef     = useRef(null);
  const containerRef = useRef(null);
  const engineRef    = useRef(null);
  const syncRef      = useRef(null);
  const isActive     = activeAudioId === id;
  const audioSrc     = src.replace(/\.(mp4|webm)(\?.*)?$/i, '.mp3$2');

  // ── Drift correction ───────────────────────────────────────────────────────
  const startSync = useCallback(() => {
    clearInterval(syncRef.current);
    syncRef.current = setInterval(() => {
      const v = videoRef.current, a = audioRef.current;
      if (!v || !a || v.paused || a.paused) return;
      if (Math.abs(v.currentTime - a.currentTime) > DRIFT_THRESHOLD) {
        a.currentTime = v.currentTime;
      }
    }, SYNC_INTERVAL_MS);
  }, []);

  const stopSync = useCallback(() => clearInterval(syncRef.current), []);

  // ── MSE engine ────────────────────────────────────────────────────────────
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const usesMSE = typeof MediaSource !== 'undefined';

    if (usesMSE) {
      const engine = new StreamEngine(video, src);
      engineRef.current = engine;

      // Audio starts downloading immediately, independent of video
      // (audio element with src already triggers browser fetch)

      engine.start().then(() => {
        // First video chunk ready — align audio and play both
        const audio = audioRef.current;
        if (audio && isActive) {
          audio.currentTime = video.currentTime;
          audio.play().catch(() => {});
        }
        video.play().catch(() => {});
      });

      const onTimeUpdate = () => engine.onTimeUpdate();
      const onSeeking    = () => engine.onSeeking();
      video.addEventListener('timeupdate', onTimeUpdate);
      video.addEventListener('seeking',    onSeeking);

      return () => {
        video.removeEventListener('timeupdate', onTimeUpdate);
        video.removeEventListener('seeking',    onSeeking);
        engine.destroy();
        engineRef.current = null;
      };
    } else {
      video.src = src;
      video.play().catch(() => {});
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [src]);

  // ── Active audio control ───────────────────────────────────────────────────
  useEffect(() => {
    const audio = audioRef.current;
    const video = videoRef.current;
    if (!audio || !video) return;

    if (isActive) {
      audio.currentTime = video.currentTime;
      audio.play().catch(() => {});
      startSync();
    } else {
      audio.pause();
      stopSync();
    }
    return () => stopSync();
  }, [isActive, startSync, stopSync]);

  // ── Intersection observer ──────────────────────────────────────────────────
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => onVisibilityChange(id, e.isIntersecting && e.intersectionRatio > 0.5),
      { threshold: 0.5 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [id, onVisibilityChange]);

  return (
    <div ref={containerRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      {/* Audio loads independently — no waiting for video */}
      <audio
        ref={audioRef}
        src={audioSrc}
        loop
        preload="auto"
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
